package com.google.gson.internal.bind;
import com.google.gson.JsonSyntaxException;
import com.google.gson.TypeAdapter;
import com.google.gson.TypeAdapterFactory;
import com.google.gson.internal.JavaVersion;
import com.google.gson.internal.PreJava9DateFormatProvider;
import com.google.gson.internal.bind.util.ISO8601Utils;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import java.text.ParseException;
import java.text.ParsePosition;
import java.util.Objects;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.internal.bind.DefaultDateTypeAdapter;
import com.google.gson.internal.bind.DefaultDateTypeAdapter.DateType;
import com.google.gson.stream.JsonWriter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.InOrder;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Field;
import java.text.DateFormat;
import java.text.SimpleDateFormat;
import java.util.ArrayList;
import java.util.Date;
import java.util.List;
import java.util.Locale;

public class DefaultDateTypeAdapterTest {

    private DefaultDateTypeAdapter<Date> adapter;
    private JsonWriter jsonWriter;
    private StringWriter stringWriter;

    @BeforeEach
    public void setUp() throws Exception {
        // Create a DateType mock or dummy implementation for Date
        DateType<Date> dateType = new DateType<Date>() {
            @Override
            public Date fromMillis(long millis) {
                return new Date(millis);
            }

            @Override
            public long toMillis(Date value) {
                return value.getTime();
            }
        };

        // Instantiate adapter with date pattern constructor via reflection (private constructor)
        // We'll use the constructor with (DateType<T>, String) signature
        var constructor = DefaultDateTypeAdapter.class.getDeclaredConstructor(DateType.class, String.class);
        constructor.setAccessible(true);
        adapter = (DefaultDateTypeAdapter<Date>) constructor.newInstance(dateType, "yyyy-MM-dd'T'HH:mm:ss'Z'");

        // Prepare JsonWriter backed by StringWriter to capture output
        stringWriter = new StringWriter();
        jsonWriter = new JsonWriter(stringWriter);
    }

    @Test
    public void testWrite_NullValue_CallsNullValueOnJsonWriter() throws IOException {
        // Use spy to verify method calls on jsonWriter
        JsonWriter spyWriter = spy(jsonWriter);

        adapter.write(spyWriter, null);

        verify(spyWriter).nullValue();
        verify(spyWriter, never()).value(anyString());
        assertEquals("", stringWriter.toString());
    }

    @Test
    public void testWrite_ValidDate_FormatsAndWritesValue() throws Exception {
        Date date = new Date(0L); // Epoch

        // Access dateFormats field and replace first element with a known DateFormat instance to control output
        Field dateFormatsField = DefaultDateTypeAdapter.class.getDeclaredField("dateFormats");
        dateFormatsField.setAccessible(true);
        @SuppressWarnings("unchecked")
        List<DateFormat> dateFormats = (List<DateFormat>) dateFormatsField.get(adapter);

        // Clear existing formats and add a SimpleDateFormat with fixed locale and pattern
        dateFormats.clear();
        DateFormat fixedFormat = new SimpleDateFormat("yyyy-MM-dd HH:mm:ss", Locale.US);
        dateFormats.add(fixedFormat);

        // Spy on jsonWriter
        JsonWriter spyWriter = spy(jsonWriter);

        adapter.write(spyWriter, date);

        // Verify synchronization by verifying format called on dateFormat inside synchronized block
        // Cannot verify synchronization directly, but can verify output correctness and call order

        // Expected formatted string
        String expectedFormatted = fixedFormat.format(date);

        InOrder inOrder = inOrder(spyWriter);
        inOrder.verify(spyWriter).value(expectedFormatted);

        // No nullValue call
        verify(spyWriter, never()).nullValue();

        // The stringWriter should contain the JSON string value (quoted)
        // JsonWriter.value(String) writes the string value in JSON format including quotes
        // So stringWriter.toString() should contain the quoted string
        String output = stringWriter.toString();
        assertTrue(output.contains(expectedFormatted));
    }
}
